{
    struct{int a;int b;} * x = func_args->arg_info;
    int n1 = x->a;
    int n3 = x->b;

    initialise_arrays(__func__);
    gettimeofday(&func_args->t1, NULL);

    for (int nl = 0; nl < iterations; nl++) {
        if (n3 == 1) {
            for (int i = n1-1; i < LEN_1D; i += 1) {
                a[i] += b[i];
            }
        } else if (n3 == 2) {
            for (int i = n1-1; i < LEN_1D; i += 2) {
                a[i] += b[i];
            }
        } else if (n3 == 4) {
            for (int i = n1-1; i < LEN_1D; i += 4) {
                a[i] += b[i];
            }
        } else {
            for (int i = n1-1; i < LEN_1D; i += n3) {
                a[i] += b[i];
            }
        }
        dummy(a, b, c, d, e, aa, bb, cc, 0.);
    }

    gettimeofday(&func_args->t2, NULL);
    return calc_checksum(__func__);
}

real_t s1113(struct args_t * func_args)
{

//    linear dependence testing
//    one iteration dependency on a(LEN_1D/2) but still vectorizable

    initialise_arrays(__func__);
    gettimeofday(&func_args->t1, NULL);

    for (int nl = 0; nl < 2*iterations; nl++) {
        real_t temp_val = a[LEN_1D/2];
        for (int i = 0; i < LEN_1D; i++) {
            a[i] = temp_val + b[i];
        }
        dummy(a, b, c, d, e, aa, bb, cc, 0.);
    }

    gettimeofday(&func_args->t2, NULL);
    return calc_checksum(__func__);
}

real_t s122(struct args_t * func_args)
{

//    induction variable recognition
//    variable lower and upper bound, and stride
//    reverse data access and jump in data access

    struct{int a;int b;} * x = func_args->arg_info;
    int n1 = x->a;
    int n3 = x->b;

    initialise_arrays(__func__);
    gettimeofday(&func_args->t1, NULL);

    int j, k;
    int k_vals[LEN_1D];
    int idx_vals[LEN_1D];
    int count;

    for (int nl = 0; nl < iterations; nl++) {
        j = 1;
        k = 0;

        // Precompute indices to break recurrence dependency
        count = 0;
        for (int i = n1-1; i < LEN_1D; i += n3) {
            k += j;
            k_vals[count] = k;
            idx_vals[count] = i;
            count++;
        }

        // Vectorizable loop using precomputed indices
        real_t * __restrict__ a_ptr = a;
        real_t * __restrict__ b_ptr = b;
        #pragma clang loop vectorize(enable)
        for (int c = 0; c < count; c++) {
            a_ptr[idx_vals[c]] += b_ptr[LEN_1D - k_vals[c]];
        }

        dummy(a, b, c, d, e, aa, bb, cc, 0.);
    }

    gettimeofday(&func_args->t2, NULL);
    return calc_checksum(__func__);
}
